import { getCartDeviceId } from "../cart/cart";
import { getLoggedInCid } from "../auth/session";
import {
  createWishlistItem,
  deleteWishlistItem,
  getWishlistByCustomer,
  getWishlistByDevice,
} from "./wishlist";

export function getWishlistProductId(item) {
  if (item?.pid && typeof item.pid === "object") return item.pid._id || item.pid.id;
  return item?.pid || item?.productId || item?.id || null;
}

function getCreatedWishlistItem(payload) {
  if (!payload) return null;

  return (
    payload?.data?.data ||
    payload?.data?.wishlist ||
    payload?.data?.item ||
    payload?.data?.wishlistItem ||
    payload?.wishlist ||
    payload?.item ||
    payload?.wishlistItem ||
    null
  );
}

export async function loadWishlistItems() {
  const cid = getLoggedInCid();
  const deviceId = getCartDeviceId();
  if (!cid && !deviceId) return [];

  const res = cid
    ? await getWishlistByCustomer(cid)
    : await getWishlistByDevice(deviceId);

  return Array.isArray(res?.data?.data)
    ? res.data.data
    : Array.isArray(res?.data)
      ? res.data
      : [];
}

export async function toggleWishlistProduct(product, wishlistItems) {
  const productId = product?._id || product?.id || product?.productId;
  if (!productId) return { items: wishlistItems, changed: false };

  const existingItem = wishlistItems.find(
    (item) => String(getWishlistProductId(item)) === String(productId)
  );

  if (existingItem) {
    let itemToDelete = existingItem;

    if (!itemToDelete._id || String(itemToDelete._id).startsWith("pending-")) {
      const latestItems = await loadWishlistItems();
      itemToDelete = latestItems.find(
        (item) => String(getWishlistProductId(item)) === String(productId)
      );
    }

    if (!itemToDelete?._id || String(itemToDelete._id).startsWith("pending-")) {
      return {
        items: wishlistItems.filter(
          (item) => String(getWishlistProductId(item)) !== String(productId)
        ),
        changed: true,
      };
    }

    await deleteWishlistItem(itemToDelete._id);
    return {
      items: wishlistItems.filter((item) => item._id !== itemToDelete._id),
      changed: true,
    };
  }

  const cid = getLoggedInCid();
  const deviceId = getCartDeviceId();
  const res = await createWishlistItem({
    cid: cid || null,
    pid: productId,
    divid: deviceId,
    qty: 1,
    variantId: product.defaultVariant?._id || product.variantId || null,
    venderid: product.vendorId || product.venderid || null,
    offerDiscount: product.discount || 0,
  });

  const created = getCreatedWishlistItem(res);
  if (!created) {
    try {
      const latestItems = await loadWishlistItems();
      const latestItem = latestItems.find(
        (item) => String(getWishlistProductId(item)) === String(productId)
      );

      return {
        items: latestItem
          ? latestItems
          : [
              ...wishlistItems,
              {
                _id: `pending-${productId}`,
                pid: productId,
                productId,
              },
            ],
        changed: true,
      };
    } catch {
      return {
        items: [
          ...wishlistItems,
          {
            _id: `pending-${productId}`,
            pid: productId,
            productId,
          },
        ],
        changed: true,
      };
    }
  }

  return {
    items: [...wishlistItems, created],
    changed: true,
  };
}
